using System;

using System.Threading;



namespace produttore_consumatore_thr

{

    class Program

    {

        // variabile globale comune ai threads

        static int n;

        // semafori di sincronizzazione.

        static Semaphore semc;

        static Semaphore semp;



        // thread del consumatore

        static void cons()

        {

            while (true)

            {

                semc.WaitOne();   // eventuale stop del consumatore se il produttore non ha ancora prodotto

                Console.WriteLine("Consumato: " + n);  // segnala che un dato è stato letto dalla variabile globale (consumato)

                Thread.Sleep(500);  // regolatore di velocità del thread

                semp.Release();        // da via libera al produttore

            }

        }



        // thread del produttore

        static void prod()

        {

            while (true)

            {

                semp.WaitOne();   // eventuale stop del produttore se il consumatore non ha ancora consumato

                n++;     // produce nuovo dato

                Console.WriteLine("Prodotto: " + n);     // segnala che un dato è stato scritto nella variabile comune

                Thread.Sleep(200);     // regolatore di velocità del thread

                semc.Release();

            }

        }



        static void Main(string[] args)

        {

            Thread thc, thp;



            n = 0;



            // semafori di sincronizzazione.

            // Il produttore è pronto inizialmente per produrre e quindi il suo semaforo

            // a valore alto, e di conseguenza risulta invece interdetto il semaforo  che

            // controlla il consumatore

            semc = new Semaphore(0, 1);

            semp = new Semaphore(1, 1);



            // creazione e lancio dei threads produttore e consumatore

            thc = new Thread(cons);

            thp = new Thread(prod);

            thc.Start();

            thp.Start();

        }

    }

}

