class Program

{

  static BlockingCollection<int> coda = new BlockingCollection<int>(10);    



  static void cons()

  {

      int n;



      while (true)

      {

          n = coda.Take();

          Console.WriteLine("Lunghezza coda: " + coda.Count);

          Console.WriteLine("Consumato: " + n);

          Thread.Sleep(500);

      }

  }



  static void prod()

  {

      int n = 0;



      while (true)

      {

         n++;

         coda.Add(n);

         Console.WriteLine("Prodotto: " + n);        

         Thread.Sleep(300);          

      }

  }



  static void Main()

  {

      Thread th_cons, th_prod;



      th_cons = new Thread(cons);

      th_prod = new Thread(prod);    



      th_cons.Start();

      th_prod.Start();

  }

}

using System;

using System.Threading;



namespace produttore_consumatore_thr

{

    class Program

    {

        // variabili globale comune ai threads

        static int n, cont;



        // thread del consumatore

        static void cons()

        {

            while (true)

            {

                while (n == 0) ;    // stoppa il thread finchè il dato non è stato prodotto

                Console.WriteLine("Consumato: " + n);  // segnala che un dato è stato letto dalla variabile globale (consumato)

                n = 0;

                Thread.Sleep(500);  // regolatore di velocità del thread              

            }

        }



        // thread del produttore

        static void prod()

        {

            while (true)

            {

                while (n != 0) ;   // stoppa il thread finchè il dato non è stato consumato

                cont++;     // produce nuovo dato

                n = cont;

                Console.WriteLine("Prodotto: " + n);     // segnala che un dato è stato scritto nella variabile comune

                Thread.Sleep(200);     // regolatore di velocità del thread                

            }

        }



        static void Main(string[] args)

        {

            Thread thc, thp;



            n = 0;

            cont = 0;



            // creazione e lancio dei threads produttore e consumatore

            thc = new Thread(cons);

            thp = new Thread(prod);

            thc.Start();

            thp.Start();

        }

    }

}

