using System;

using System.Net;

using System.Net.Sockets;

using System.Text;

using System.Threading;

namespace prod_socket

{

    class Program

    {

        static int n = 0;



        // routine-thread che viene attivata in parallelo, per ogni consumatore

        // che si collega al produttore (server)

        static void invio_dati(Object obj)

        {

            bool esci = false;

            byte[] dati;

            Socket sk = (Socket) obj;



            while (! esci)

            {

                n++;

                dati = BitConverter.GetBytes(n);

                try {     // se si verifica errore il consumatore si è sganciato....

                    sk.Send(dati);

                    Console.WriteLine("Prodotto: " + n);

                }

                catch (SocketException)

                {   // allora il produttore chiude la socket ed esce dal ciclo di trasmissione

                    Console.WriteLine("Un consumatore si è sganciato.");

                    sk.Close();

                    esci = true;

                }

            }

        }



        static void Main(string[] args)

        {

            Socket sk;  // socket di ascolto

            Socket sk_con;   // socket di connessione

            IPEndPoint ep;

            Thread thn;

            int n, nconn;



            // definisce le tipologie di rete e protocollo su cui la socket deve operare

            sk = new Socket(AddressFamily.InterNetwork, SocketType.Stream, ProtocolType.Tcp);





            // definisce l'host (indirizzo) e la porta sulla quale connettersi

            ep = new IPEndPoint(IPAddress.Loopback, 5000);



            sk.Bind(ep);     // associa i parametri di connessione alla socket sk



            sk.Listen(2);   // comanda alla socket di mettersi in ascolto di connessioni

            // (max client in attesa 2)



            nconn = 0;

            while (true)

            {

                Console.WriteLine("In attesa di connessione....");

                //sk_conn[nconn] = sk.Accept();     // bloccante in attesa di una richiesta di connessione

                sk_con = sk.Accept();



                thn = new Thread(invio_dati);

                thn.Start(sk_con);



                nconn++;

            }



        }

    }

}
